// Safely parse and validate content calendar JSON from AI agent output
try {
  const rawOutput = $input.all()[0]?.json?.output;

  if (!rawOutput) {
    throw new Error('No output received from AI agent');
  }

  // Clean JSON string from markdown code blocks
  const cleanJsonString = rawOutput
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  // Parse the JSON array
  const calendarArray = JSON.parse(cleanJsonString);

  // Validate it's an array
  if (!Array.isArray(calendarArray)) {
    throw new Error('Parsed content is not an array');
  }

  // Validate array is not empty
  if (calendarArray.length === 0) {
    throw new Error('Content calendar array is empty');
  }

  // Map each day to a separate item for batch processing
  return calendarArray.map((item, index) => {
    // Validate required fields
    const requiredFields = ['Day_Number', 'Authority_Pillar', 'Platform_Target', 'Content_Format'];
    const missingFields = requiredFields.filter(field => !item[field]);

    if (missingFields.length > 0) {
      console.warn(`Item ${index + 1} missing fields: ${missingFields.join(', ')}`);
    }

    return {
      json: item,
      pairedItem: { item: 0 }
    };
  });

} catch (error) {
  // Return error item for debugging
  return [{
    json: {
      error: true,
      message: error.message,
      rawInput: $input.all()[0]?.json?.output?.substring(0, 500) || 'No input'
    },
    pairedItem: { item: 0 }
  }];
}

// Log error details for debugging
const errorItem = $input.all()[0].json;

return [{
  json: {
    error: true,
    errorType: 'Content Calendar Parsing Failed',
    message: errorItem.message || 'Unknown error',
    timestamp: new Date().toISOString(),
    rawInputPreview: errorItem.rawInput || 'No data'
  }
}];

